public void changeBOMRouteVersions(TransDate  _bomDate, boolean _pmfAssignQty)
{
    InventDim  inventDim;
    ProdTable prodtable;
    Qty             input;
    FormRun      fromrun = this;
    FormDataSource      prodTable_ds = fromrun.dataSource(formDataSourceStr(ProdTableCreate, ProdTable));
    FormDataSource      inventDim_ds = fromrun.dataSource(formDataSourceStr(ProdTableCreate, InventDim));

    prodtable = prodTable_ds.cursor();
    inventDim = inventDim_ds.cursor();

    next changeBOMRouteVersions( _bomDate,  _pmfAssignQty);

    //if (prodtable.BOMId == '')
    //{
    //    prodtable.BOMId = '';
    //}

    prodtable.BOMId = '';

}

/// <summary>
///
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormControlEventHandler(formControlStr(ProdTableCreate, ProdTable_ETGBOMId1), FormControlEventType::Lookup)]
public static void ProdTable_ETGBOMId1_OnLookup(FormControl sender, FormControlEventArgs e)
{
    PmfFormCtrl_ProdTableCreate pmfFormCtrl_ProdTableCreate;
    str         _filterStr;
    FormRun     formrun = sender.formRun();
    pmfFormCtrl_ProdTableCreate = PmfFormCtrl_ProdTableCreate::newFromForm(formrun);
    ProdTable   prodtable = formrun.dataSource(formDataSourceStr(ProdTableCreate, ProdTable)).cursor();
    InventDim   inventdim = formrun.dataSource(formDataSourceStr(ProdTableCreate, InventDim)).cursor();
    FormControl             _formControl              = formRun.design(0).controlName("ProdTable_ETGBOMId1");

    if (#PmfEnabled)
    {

         if (#PmfEnabled)
            {
            InventTable::lookupFormulaId(_formControl, prodtable.ItemId, inventdim);

            }
            else
            {
            InventTable::lookupBOMId(_formControl, prodTable.ItemId,
                    inventDim);
            }
    }
    else
    {
        InventTable::lookupBOMId(_formControl, prodTable.ItemId, inventDim, true, false);
    }
    if(ETGCanadaParameters::find().EnableSubContractingPO)
    {
        // Prevent super / multiple lookup calls
        FormControlCancelableSuperEventArgs cancelArgs = e as FormControlCancelableSuperEventArgs;
        if (cancelArgs)
        {
            cancelArgs.cancelSuperCall();
        }
    }
}

/// <summary>
///
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormDataFieldEventHandler(formDataFieldStr(ProdTableCreate, ProdTable, ETGBOMId1), FormDataFieldEventType::Validated)]
public static void ETGBOMId1_OnValidated(FormDataObject sender, FormDataFieldEventArgs e)
{
    PmfFormCtrl_ProdTableCreate pmfFormCtrl_ProdTableCreate;
    str         _filterStr;
    boolean ret;

    var args = e as FormDataFieldCancelEventArgs;
    FormRun     formrun = sender.datasource().formRun();
    pmfFormCtrl_ProdTableCreate = PmfFormCtrl_ProdTableCreate::newFromForm(formrun);
    ProdTable   prodtable = formrun.dataSource(formDataSourceStr(ProdTableCreate, ProdTable)).cursor();
    InventDim   inventdim = formrun.dataSource(formDataSourceStr(ProdTableCreate, InventDim)).cursor();



    ret = ProdTable::validateBOMId(prodTable.bomId,prodTable.ItemId,inventDim);
    if (ret == false)
    {
        args.cancel(true);
    }

}

