/// <summary>
/// Lookup for Parent entity
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormControlEventHandler(formControlStr(ProdTableCreate, ProdTable_ETGParentEntity), FormControlEventType::Lookup)]
public static void ProdTable_ETGParentEntity_OnLookup(FormControl sender, FormControlEventArgs e)
{
    FormControlCancelableSuperEventArgs cancelEventArgs = e as FormControlCancelableSuperEventArgs;
    cancelEventArgs.cancelSuperCall();

    Query query = new Query();
    QueryBuildDataSource queryBuildDataSource;
    QueryBuildRange queryBuildRange;
    SysTableLookup sysTableLookup = SysTableLookup::newParameters(tableNum(ETGLegalEntityListForSUbcontractingProdOrder), sender);

    sysTableLookup.addLookupField(fieldNum(ETGLegalEntityListForSUbcontractingProdOrder,LegalEntityName));
    sysTableLookup.addLookupField(fieldNum(ETGLegalEntityListForSUbcontractingProdOrder,Name));

    queryBuildDataSource = query.addDataSource(tableNum(ETGLegalEntityListForSUbcontractingProdOrder));
    sysTableLookup.parmQuery(query);
    sysTableLookup.performFormLookup();
}

/// <summary>
/// Lookup for raw material warehouse from parent entity
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormControlEventHandler(formControlStr(ProdTableCreate, ProdTable_ETGParentWareHouse), FormControlEventType::Lookup)]
public static void ProdTable_ETGParentWareHouse_OnLookup(FormControl sender, FormControlEventArgs e)
{
    FormControlCancelableSuperEventArgs cancelEventArgs = e as FormControlCancelableSuperEventArgs;
    cancelEventArgs.cancelSuperCall();

    Query query = new Query();
    QueryBuildDataSource queryBuildDataSource;
    QueryBuildRange queryBuildRange;
    SysTableLookup sysTableLookup =
        SysTableLookup::newParameters(tableNum(InventLocation), sender);

    sysTableLookup.addLookupField(fieldNum(InventLocation,InventLocationId));
    sysTableLookup.addLookupField(fieldNum(InventLocation,Name));

    ProdTable prodTable = sender.formRun().dataSource(1).cursor();
    queryBuildDataSource = query.addDataSource(tableNum(InventLocation));
    queryBuildDataSource.company(prodTable.ETGParentEntity);

    sysTableLookup.parmQuery(query);
    sysTableLookup.performFormLookup();
}
